def values(self, *keys):
    """
    Restituisce i valori del record, con la possibilità di filtrare per includere solo determinati valori in base all'indice o alla chiave.

    :param keys: indici o chiavi degli elementi da includere; se non viene fornito nessun parametro, verranno inclusi tutti i valori
    :return: lista di valori
    :rtype: list
    """
    # Se non vengono fornite chiavi, restituisci tutti i valori
    if not keys:
        return list(self._valori.values())

    # Lista per memorizzare i valori filtrati
    valori_filtrati = []

    # Itera sulle chiavi fornite
    for chiave in keys:
        # Se la chiave è un intero, usalo come indice
        if isinstance(chiave, int):
            # Converti il dizionario in lista per accesso tramite indice
            lista_valori = list(self._valori.values())
            # Controlla se l'indice è valido
            if 0 <= chiave < len(lista_valori):
                valori_filtrati.append(lista_valori[chiave])
        # Altrimenti usa la chiave per accedere al dizionario
        else:
            if chiave in self._valori:
                valori_filtrati.append(self._valori[chiave])

    return valori_filtrati

def data(self, *keys):
    # Se non vengono fornite chiavi, restituisci tutti i dati
    if not keys:
        return dict(zip(self._fields, self._data))

    # Dizionario per memorizzare i risultati
    risultato = {}

    # Itera attraverso le chiavi fornite
    for chiave in keys:
        # Se la chiave è un intero, usalo come indice
        if isinstance(chiave, int):
            # Solleva IndexError se l'indice è fuori dai limiti
            if chiave >= len(self._fields):
                raise IndexError(f"Indice {chiave} fuori dai limiti")
            nome_campo = self._fields[chiave]
            valore = self._data[chiave]
        # Altrimenti usa la chiave come nome del campo
        else:
            nome_campo = chiave
            # Trova l'indice del campo se esiste
            try:
                indice = self._fields.index(chiave)
                valore = self._data[indice]
            except ValueError:
                valore = None

        risultato[nome_campo] = valore

    return risultato

def parse_version(s: str) -> tuple[int, ...]:
    """versione semplificata per il confronto delle versioni"""
    # dividi la stringa sui punti e converti ogni elemento in intero
    numeri_versione = []

    # rimuovi eventuali spazi bianchi
    s = s.strip()

    # gestisci stringa vuota
    if not s:
        return tuple()

    # dividi sui punti e converti in numeri
    parti = s.split('.')

    for parte in parti:
        try:
            # converti ogni parte in intero
            numero = int(parte)
            numeri_versione.append(numero)
        except ValueError:
            # ignora parti non numeriche
            continue

    return tuple(numeri_versione)

def minimalBases(classes):
    """
    Riduce una lista di classi base al suo equivalente minimo ordinato.
    """
    # Rimuove le classi duplicate mantenendo l'ordine
    classi_uniche = []
    for classe in classes:
        if classe not in classi_uniche:
            classi_uniche.append(classe)

    # Rimuove le classi che sono già ereditate da altre classi
    classi_minime = []
    for i, classe in enumerate(classi_uniche):
        # Flag per verificare se la classe corrente è necessaria
        necessaria = True

        # Controlla tutte le altre classi
        for altra_classe in classi_uniche[i+1:]:
            # Se la classe corrente è una superclasse di un'altra classe
            if issubclass(altra_classe, classe):
                necessaria = False
                break

        if necessaria:
            classi_minime.append(classe)

    return classi_minime

