def names(self, all=False): # pylint:disable=redefined-builtin
    """Restituisce i nomi degli attributi definiti dall'interfaccia."""
    if not all:
        # Restituisce solo gli attributi non nascosti (che non iniziano con underscore)
        return [nome for nome in self.__dict__ if not nome.startswith('_')]
    else:
        # Restituisce tutti gli attributi, inclusi quelli nascosti
        return list(self.__dict__.keys())

def is_fill_request_seq(seq):
    # Importa il tipo FillRequest e Source
    from typing import Sequence
    from fillrequest import FillRequest, Source

    # Controlla se seq è di tipo Source
    if isinstance(seq, Source):
        return False

    # Controlla se seq è direttamente un FillRequest
    if isinstance(seq, FillRequest):
        return True

    # Controlla se seq è una sequenza
    if not isinstance(seq, Sequence):
        return False

    # Controlla se la sequenza contiene almeno un FillRequest
    for elemento in seq:
        if isinstance(elemento, FillRequest):
            return True

    # Se non trova FillRequest restituisce False
    return False

def is_fill_request_el(obj):
    # Controlla se l'oggetto ha i metodi fill e request
    metodi_richiesti = ['fill', 'request']

    # Verifica che entrambi i metodi siano presenti e chiamabili
    for metodo in metodi_richiesti:
        if not hasattr(obj, metodo) or not callable(getattr(obj, metodo)):
            return False

    return True

