def generate_default_observer_schema_dict(manifest_dict, first_level=False):
    # Inizializza il dizionario di output
    schema_dict = {}

    # Itera su tutte le chiavi e valori del manifest
    for chiave, valore in manifest_dict.items():

        # Se è il primo livello, copia i campi identificativi
        if first_level and chiave in ['apiVersion', 'kind', 'metadata']:
            schema_dict[chiave] = valore
            continue

        # Se il valore è un dizionario, chiamata ricorsiva
        if isinstance(valore, dict):
            schema_dict[chiave] = generate_default_observer_schema_dict(valore)

        # Se il valore è una lista, chiamata alla funzione per liste
        elif isinstance(valore, list):
            from kubernetes_observer.utils import generate_default_observer_schema_list
            schema_dict[chiave] = generate_default_observer_schema_list(valore)

        # Altrimenti imposta il valore a None
        else:
            schema_dict[chiave] = None

    return schema_dict

def update_last_applied_manifest_dict_from_resp(
    last_applied_manifest, observer_schema, response
):
    # Itera su tutti i campi nello schema dell'osservatore
    for campo, valore_schema in observer_schema.items():
        # Se il campo non è presente nella risposta, solleva KeyError
        if campo not in response:
            raise KeyError(f"Campo '{campo}' non trovato nella risposta")

        # Se il campo non esiste nel manifest, inizializzalo
        if campo not in last_applied_manifest:
            if isinstance(valore_schema, dict):
                last_applied_manifest[campo] = {}
            elif isinstance(valore_schema, list):
                last_applied_manifest[campo] = []
            else:
                last_applied_manifest[campo] = response[campo]
                continue

        # Gestisci ricorsivamente dizionari e liste nidificati
        if isinstance(valore_schema, dict):
            update_last_applied_manifest_dict_from_resp(
                last_applied_manifest[campo],
                valore_schema,
                response[campo]
            )
        elif isinstance(valore_schema, list) and len(valore_schema) > 0:
            from update_last_applied_manifest_list_from_resp import update_last_applied_manifest_list_from_resp
            update_last_applied_manifest_list_from_resp(
                last_applied_manifest[campo],
                valore_schema[0],
                response[campo]
            )
        else:
            # Aggiorna il valore del campo
            last_applied_manifest[campo] = response[campo]

def generate_default_observer_schema(app):
    # Dizionario per memorizzare lo schema di osservazione
    schema_osservazione = {}

    # Itera attraverso ogni manifesto nell'applicazione
    for manifesto in app.spec.manifest:
        # Ottieni il tipo di risorsa e il nome
        tipo_risorsa = manifesto.get("kind")
        nome_risorsa = manifesto.get("metadata", {}).get("name")

        # Se la risorsa non ha già uno schema personalizzato
        if nome_risorsa not in app.spec.observer_schema:
            # Crea uno schema predefinito per questa risorsa
            schema_osservazione[nome_risorsa] = {
                "tipo": tipo_risorsa,
                "campi_osservati": [
                    "status",
                    "metadata.generation",
                    "metadata.resourceVersion"
                ]
            }

    # Aggiorna lo schema di osservazione dell'applicazione
    app.spec.observer_schema.update(schema_osservazione)

    return app.spec.observer_schema
